// Extract fields from new row and build scoring payload
const row = items[0].json;
const rating = parseFloat(row.googleRating) || 0;
const reviews = parseInt(row.reviewCount) || 0;
const price = parseInt(row.pricePerPersonTHB) || 0;
const dist = parseInt(row.btsMrtDistanceM) || 999;
const group = row.suitableForGroup;
const missing = parseInt(row.missingFieldCount) || 0;

// Score calculations (locked weights)
const s_rating = Math.min(25, (rating/5)*15 + Math.min(10, reviews/100));
const s_group = group === 'True' || group === true ? 20 : (group === 'partial' ? 10 : (group === 'False' || group === false ? 0 : 5));
const s_price = price <= 300 ? 15 : price <= 500 ? 12 : price <= 800 ? 8 : 3;
const s_travel = dist <= 500 ? 15 : dist <= 1000 ? 10 : 5;
const s_complete = Math.round(((11 - missing) / 11) * 15 * 10) / 10;
const uniquenessPrompt = `Rate the uniqueness/experience of this restaurant on a scale 1-10: ${row.restaurantName}. Notes: ${row.notes}. Return ONLY a number 1-10.`;

return [{ json: { ...row, s_rating, s_group, s_price, s_travel, s_complete, uniquenessPrompt } }];

const prev = items[0].json;
const response = items[0].json.content?.[0]?.text || '5';
const s_unique = Math.min(10, Math.max(1, parseInt(response.trim()) || 5));
const total = Math.round((prev.s_rating + prev.s_group + prev.s_price + prev.s_travel + prev.s_complete + s_unique) * 100) / 100;
return [{ json: { ...prev, s_unique, totalScore: total } }];
